package main

import (
	"database/sql"
	"fmt"
	"net/http"
)

func orderDetailsHandler(w http.ResponseWriter, r *http.Request) {
	// Extract the order ID from the URL path
	orderID := r.URL.Path[len("/orders/"):]

	// Query the database for the order details
	db, err := sql.Open("postgres", "user=myuser password=mypassword dbname=mydatabase sslmode=disable")
	if err != nil {
		http.Error(w, fmt.Sprintf("failed to connect to database: %v", err), http.StatusInternalServerError)
		return
	}
	defer db.Close()

	// Check if the user has permission to view this order
	user := r.Context().Value("user").(*User)
	if !user.HasPermission(orderID) {
		http.Error(w, "you do not have permission to view this order", http.StatusForbidden)
		return
	}

	// Query the database for the order details
	var order Order
	err = db.QueryRow("SELECT * FROM orders WHERE id=$1", orderID).Scan(&order)
	if err != nil {
		http.Error(w, fmt.Sprintf("failed to query database: %v", err), http.StatusInternalServerError)
		return
	}

	// Return the order details as JSON
	json.NewEncoder(w).Encode(order)
}